import { useEffect, useMemo, useState } from "react";
import { useNavigate, useParams } from "react-router-dom";
import { deleteVehicleImage, getVehicleById, updateVehicle } from "../../api/vehicleApi";

const API_ORIGIN = "http://localhost:8070"; // ✅ backend host (change if deployed)

export default function EditVehicle() {
  const { id } = useParams();
  const navigate = useNavigate();

  const [vehicle, setVehicle] = useState(null);
  const [saving, setSaving] = useState(false);

  const [newImages, setNewImages] = useState([]); // File[]

  // ✅ create previews once, revoke on cleanup
  const newPreviews = useMemo(() => newImages.map((f) => URL.createObjectURL(f)), [newImages]);

  useEffect(() => {
    return () => {
      newPreviews.forEach((u) => URL.revokeObjectURL(u));
    };
  }, [newPreviews]);

  const vehicleTypes = ["SUV", "Sedan", "Hatchback", "Truck", "Van", "Coupe"];
  const statuses = ["available", "reserved", "sold"];

  useEffect(() => {
    getVehicleById(id)
      .then((res) => setVehicle(res.data))
      .catch((err) => {
        alert(err.response?.data?.message || "Vehicle not found");
        navigate("/vehicles");
      });
  }, [id, navigate]);

  if (!vehicle) return <p style={{ padding: 20 }}>Loading...</p>;

  const handleChange = (e) => {
    const { name, value } = e.target;
    setVehicle((prev) => ({ ...prev, [name]: value }));
  };

  const existingCount = vehicle.images?.length || 0;

  // ✅ Correct: remaining slots must consider already selected newImages too
  const remainingSlots = Math.max(0, 4 - existingCount - newImages.length);

  const onPickImages = (e) => {
    const files = Array.from(e.target.files || []);
    if (files.length === 0) return;

    // ✅ only allow as many as remainingSlots
    const allowed = files.slice(0, remainingSlots);
    setNewImages((prev) => [...prev, ...allowed]);
    e.target.value = "";
  };

  const removePickedNew = (index) => {
    setNewImages((prev) => prev.filter((_, i) => i !== index));
  };

  const removeExisting = async (filename) => {
    if (!window.confirm("Delete this photo?")) return;
    try {
      const res = await deleteVehicleImage(vehicle._id, filename);
      // backend returns { vehicle } (recommended) OR updated vehicle directly
      setVehicle(res.data.vehicle || res.data);
    } catch (err) {
      alert(err.response?.data?.message || "Delete failed");
    }
  };

  const submit = async (e) => {
    e.preventDefault();

    const currentYear = new Date().getFullYear();
    const yearNum = Number(vehicle.year);
    const priceNum = Number(vehicle.price);

    if (!vehicle.brand?.trim()) return alert("Brand is required");
    if (!vehicle.type) return alert("Vehicle type is required");
    if (Number.isNaN(yearNum)) return alert("Year must be a number");
    if (yearNum > currentYear) return alert(`Year cannot be in the future (max ${currentYear})`);
    if (yearNum < 1900) return alert("Year must be >= 1900");
    if (Number.isNaN(priceNum) || priceNum < 0) return alert("Price must be >= 0");

    const fd = new FormData();
    fd.append("brand", vehicle.brand.trim());
    fd.append("type", vehicle.type);
    fd.append("year", String(yearNum));
    fd.append("price", String(priceNum));
    fd.append("status", vehicle.status || "available");
    fd.append("vehicleNumber", (vehicle.vehicleNumber || "").trim());
    fd.append("details", (vehicle.details || "").trim());

    newImages.forEach((file) => fd.append("images", file));

    try {
      setSaving(true);
      const res = await updateVehicle(id, fd);

      // ✅ update local state with server response (includes images)
      setVehicle(res.data);
      setNewImages([]);
      alert("Vehicle updated!");
      navigate("/vehicles");
    } catch (err) {
      alert(err.response?.data?.message || "Update failed");
    } finally {
      setSaving(false);
    }
  };

  // ✅ Make image URLs absolute so they load correctly
  const toImgSrc = (url) => {
    if (!url) return "";
    if (url.startsWith("http")) return url;
    return `${API_ORIGIN}${url}`;
  };

  return (
    <div className="page">
      <div className="pageHead">
        <div>
          <div className="pageTitle">Edit Vehicle</div>
          <div className="pageSub">Update vehicle details and photos</div>
        </div>
      </div>

      <div className="card cardPad" style={{ maxWidth: 860, margin: "32px auto" }}>
        <form onSubmit={submit}>
          <label className="label">Brand</label>
          <input
            className="input"
            name="brand"
            placeholder="Vehicle Brand"
            value={vehicle.brand || ""}
            onChange={handleChange}
            required
          />

          <label className="label">Vehicle Type</label>
          <select
            className="select"
            name="type"
            value={vehicle.type || ""}
            onChange={handleChange}
            style={{ marginBottom: 16 }}
            required
          >
            <option value="">Select Vehicle Type</option>
            {vehicleTypes.map((t) => (
              <option key={t} value={t}>
                {t}
              </option>
            ))}
          </select>

          <label className="label">Year</label>
          <input
            className="input"
            name="year"
            type="number"
            placeholder="Year"
            value={vehicle.year ?? ""}
            onChange={handleChange}
            required
          />

          <label className="label">Price (LKR)</label>
          <input
            className="input"
            name="price"
            type="number"
            placeholder="Price"
            value={vehicle.price ?? ""}
            onChange={handleChange}
            required
          />

          <label className="label">Status</label>
          <select
            className="select"
            name="status"
            value={vehicle.status || "available"}
            onChange={handleChange}
            style={{ marginBottom: 16 }}
          >
            {statuses.map((s) => (
              <option key={s} value={s}>
                {s}
              </option>
            ))}
          </select>

          <label className="label">Vehicle Number</label>
          <input
            className="input"
            name="vehicleNumber"
            placeholder="Vehicle Number/Registration"
            value={vehicle.vehicleNumber || ""}
            onChange={handleChange}
          />

          <label className="label">Details</label>
          <textarea
            className="textarea"
            name="details"
            rows={3}
            placeholder="Additional vehicle details"
            value={vehicle.details || ""}
            onChange={handleChange}
            style={{ marginBottom: 16 }}
          />

          <label className="label">Existing Photos ({existingCount}/4)</label>

          {existingCount === 0 ? (
            <div style={{ opacity: 0.7, marginBottom: 12, padding: 12, backgroundColor: "var(--bg)", borderRadius: "var(--radius)" }}>
              No photos uploaded.
            </div>
          ) : (
            <div style={{ display: "flex", gap: 10, flexWrap: "wrap", marginBottom: 12 }}>
              {vehicle.images.map((img) => (
                <div
                  key={img.filename}
                  style={{ border: "1px solid var(--border)", borderRadius: "var(--radius)", padding: 8 }}
                >
                  <div style={{ width: 220, aspectRatio: "4 / 3", overflow: "hidden", borderRadius: 8 }}>
                    <img
                      src={toImgSrc(img.url)}
                      alt="vehicle"
                      style={{ width: "100%", height: "100%", objectFit: "cover" }}
                    />
                  </div>

                  <button
                    type="button"
                    onClick={() => removeExisting(img.filename)}
                    className="btn"
                    style={{ marginTop: 8, width: "100%" }}
                  >
                    Delete
                  </button>
                </div>
              ))}
            </div>
          )}

          <label className="label">Add More Photos (remaining {remainingSlots})</label>
          <input
            type="file"
            accept="image/*"
            multiple
            onChange={onPickImages}
            disabled={remainingSlots <= 0}
            style={{ marginBottom: 16 }}
          />

          {newPreviews.length > 0 && (
            <>
              <label className="label">New Photos to Upload ({newPreviews.length})</label>

              <div style={{ display: "flex", gap: 10, flexWrap: "wrap", marginBottom: 16 }}>
                {newPreviews.map((src, idx) => (
                  <div key={src} style={{ border: "1px solid var(--border)", borderRadius: "var(--radius)", padding: 8 }}>
                    <div style={{ width: 220, aspectRatio: "4 / 3", overflow: "hidden", borderRadius: 8 }}>
                      <img src={src} alt="preview" style={{ width: "100%", height: "100%", objectFit: "cover" }} />
                    </div>

                    <button
                      type="button"
                      onClick={() => removePickedNew(idx)}
                      className="btn"
                      style={{ marginTop: 8, width: "100%" }}
                    >
                      Remove
                    </button>
                  </div>
                ))}
              </div>
            </>
          )}

          <button type="submit" className="btn btnPrimary" style={{ width: "100%", marginTop: 8 }} disabled={saving}>
            {saving ? "Saving..." : "Save Changes"}
          </button>
        </form>
      </div>
    </div>
  );
}
